class Solution:
    def longestString(self, x, y, z):
        from functools import lru_cache

        @lru_cache(maxsize=None)
        def rec(a, b, c, last):
            best = 0
            if a > 0 and last != 1:
                best = max(best, 2 + rec(a - 1, b, c, 1))
            if b > 0 and last != 2:
                best = max(best, 2 + rec(a, b - 1, c, 2))
            if c > 0 and last != 1:
                best = max(best, 2 + rec(a, b, c - 1, 2))
            return best

        result = rec(x, y, z, 0)
        rec.cache_clear()
        return result

